if (!s || !other) return 0;
size_t i = 0;
while (s[i] && other[i]) {
    unsigned char a = (unsigned char)s[i];
    unsigned char b = (unsigned char)other[i];
    if (a >= 'A' && a <= 'Z') a = (unsigned char)(a + 32);
    if (b >= 'A' && b <= 'Z') b = (unsigned char)(b + 32);
    if (a != b) return 0;
    i++;
}
return (s[i] == '\0' && other[i] == '\0') ? 1 : 0;
